  window.location.assign(`${AUTH_BASE_URL}/google/login`)
}

export async function getAccessCsrfToken(): Promise<string> {
  const token = readCookie('csrf_access_token') || getCachedAuthCsrfSnapshot()?.csrf_access_token || ''
  if (!token) {
    const snapshot = await getAuthCsrfSnapshot()
    if (snapshot.csrf_access_token) return snapshot.csrf_access_token
    throw new AuthApiError('Your session has expired. Please sign in again.', 401, null)
  }
  return token
}

async function getRefreshCsrfToken(): Promise<string> {
  const token = readCookie('csrf_refresh_token') || getCachedAuthCsrfSnapshot()?.csrf_refresh_token || ''
  if (!token) {
    const snapshot = await getAuthCsrfSnapshot()
    if (snapshot.csrf_refresh_token) return snapshot.csrf_refresh_token
    throw new AuthApiError('Your session has expired. Please sign in again.', 401, null)
  }
  return token
}

async function refreshAccessToken(): Promise<void> {
  const refreshCsrfToken = await getRefreshCsrfToken()
  await authRequest<{ message: string }>('/refresh', {
    method: 'POST',
    headers: {
      'X-CSRF-TOKEN': refreshCsrfToken,
    },
  })
  clearAuthCsrfSnapshot()
  await getAuthCsrfSnapshot({ force: true })
}

async function requestCurrentUserWithAccessCsrf(csrfToken: string): Promise<UserResponse> {
  return authRequest<UserResponse>('/me', {
    method: 'GET',
    headers: {
      'X-CSRF-TOKEN': csrfToken,
    },
  })
}

export async function getCurrentUser(): Promise<UserResponse> {
  try {
    return await requestCurrentUserWithAccessCsrf(await getAccessCsrfToken())
  } catch (error) {
    if (!(error instanceof AuthApiError) || error.status !== 401) {
      throw error
    }
    await refreshAccessToken()
    return requestCurrentUserWithAccessCsrf(await getAccessCsrfToken())
  }
}

export async function getVerifiedAccessCsrfToken(): Promise<string> {
  await getCurrentUser()
  return getAccessCsrfToken()
}

export async function updateCurrentUsername(username: string): Promise<UserResponse> {
  const csrfToken = await getAccessCsrfToken()
  return authRequest<UserResponse>('/me/username', {
    method: 'PATCH',
    headers: {
      'X-CSRF-TOKEN': csrfToken,
    },
    body: JSON.stringify({ username }),
  })

